    31→/**
    32→ * JournalRepositoryImpl is the single source of truth for all journal-entry-related data.
    33→ * <p>
    34→ *     Responsibilities:
    35→ *     • Expose a reactive stream of {@link JournalEntryEntity} objects to the ViewModel layer.<br/>
    36→ *     • Orchestrate local caching (Room) and remote persistence (REST, Retrofit).<br/>
    37→ *     • Handle offline-first behavior and optimistic updates.<br/>
    38→ *     • Guarantee at-least-once delivery to the backend, with exponential back-off retries.<br/>
    39→ * </p>
    40→ *
    41→ * This implementation is thread-safe and lifecycle-aware, leveraging RxJava3,
    42→ * {@link AppExecutors} and {@link NetworkMonitor}.
    43→ */
    44→@SuppressLint("CheckResult")
    45→public final class JournalRepositoryImpl implements JournalRepository {
    46→
    47→    // region – Constants
    48→    private static final int REMOTE_PAGE_SIZE = 50;
    49→    private static final int MAX_RETRY_COUNT = 3;
    50→    private static final long RETRY_BACKOFF_MILLIS = TimeUnit.SECONDS.toMillis(5);
    51→    // endregion
    52→
    53→    // region – Member variables
    54→    private final JournalDao journalDao;
    55→    private final JournalApi journalApi;
    56→    private final NetworkMonitor networkMonitor;
    57→    private final AppExecutors appExecutors;
    58→
    59→    /**
    60→     * Processor that emits whenever a manual refresh is triggered.  ViewModels can subscribe
    61→     * via {@link #getJournalEntries(String)} and always receive the latest data.
    62→     */
    63→    private final BehaviorProcessor<String> manualRefreshProcessor = BehaviorProcessor.create();
    64→    // endregion
    65→
    66→    // region – Constructor
    67→    public JournalRepositoryImpl(@NonNull JournalDao journalDao,
    68→                                 @NonNull JournalApi journalApi,
    69→                                 @NonNull NetworkMonitor networkMonitor,
    70→                                 @NonNull AppExecutors appExecutors) {
    71→        this.journalDao = journalDao;
    72→        this.journalApi = journalApi;
    73→        this.networkMonitor = networkMonitor;
    74→        this.appExecutors = appExecutors;
    75→    }
    76→    // endregion
    77→
    78→    // region – Repository API
    79→
    80→    /**
    81→     * Stream of journal entries for the specified user.  The stream combines:
    82→     *  (1) Local Room DB contents      – emitted immediately for snappy UI.
    83→     *  (2) Remote fetch on subscription – populates/updates local cache.
    84→     *  (3) Manual refreshes signaled via {@link #refresh(String)}.
    85→     */
    86→    @Override
    87→    public Flowable<List<JournalEntryEntity>> getJournalEntries(@NonNull String userId) {
    88→        return Flowable.merge(
    89→                // Initial local DB subscription
    90→                journalDao.observeByUser(userId)
    91→                           .subscribeOn(Schedulers.io()),
    92→                // Manual refreshes
    93→                manualRefreshProcessor
    94→                        .filter(id -> id.equals(userId))
    95→                        .flatMapSingle(ignore -> pullLatestFromBackend(userId))
    96→                        .flatMap(ignore -> journalDao.observeByUser(userId))
    97→                        .subscribeOn(Schedulers.io())
    98→        ).distinctUntilChanged();
    99→    }
   100→
   101→    /**
   102→     * Create/Update a journal entry locally and attempt to sync with backend.
   103→     * Returns a Completable that completes once local persistence is done.
   104→     */
   105→    @Override
   106→    public Completable upsertEntry(@NonNull JournalEntryEntity entity) {
   107→        JournalEntryEntity toSave = entity;
   108→        if (toSave.getId() == null) {
   109→            // Generate local UUID if the entry is new.
   110→            toSave = entity.toBuilder()
   111→                           .setId(UUID.randomUUID().toString())
   112→                           .setPendingSync(true)
   113→                           .build();
   114→        } else {
   115→            toSave = toSave.toBuilder().setPendingSync(true).build();
   116→        }
   117→
   118→        return Completable.fromAction(() -> journalDao.upsert(toSave))
   119→                          .subscribeOn(Schedulers.io())
   120→                          .andThen(trySyncPendingEntries()); // Fire-and-forget remote sync
   121→    }
   122→
   123→    /**
   124→     * Deletes a journal entry both locally and remotely.
   125→     */
   126→    @Override
   127→    public Completable deleteEntry(@NonNull JournalEntryEntity entity) {
   128→        return Completable.fromAction(() -> journalDao.delete(entity))
   129→                          .subscribeOn(Schedulers.io())
   130→                          .andThen(networkMonitor.isConnectedSingle()
   131→                                .flatMapCompletable(isConnected -> {
   132→                                    if (!isConnected || entity.getId() == null) {
   133→                                        return Completable.complete();
   134→                                    }
   135→                                    return journalApi.deleteEntry(entity.getId())
   136→                                                     .subscribeOn(Schedulers.io())
   137→                                                     .retryWhen(errors -> errors
   138→                                                             .zipWith(Flowable.range(1, MAX_RETRY_COUNT), (err, count) -> count)
   139→                                                             .flatMap(retryCount -> {
   140→                                                                 Timber.w("Retrying delete #%d", retryCount);
   141→                                                                 return Flowable.timer(retryCount * RETRY_BACKOFF_MILLIS, TimeUnit.MILLISECONDS);
   142→                                                             })
   143→                                                     )
   144→                                                     .onErrorComplete(throwable -> {
   145→                                                         Timber.e(throwable, "Failed to delete remote entry %s – will retry later.", entity.getId());
   146→                                                         // Mark as "tombstone" so that a background sync can retry.
   147→                                                         JournalEntryEntity tombstone = entity.toBuilder()
   148→                                                                                              .setPendingDeletion(true)
   149→                                                                                              .build();
   150→                                                         journalDao.upsert(tombstone);
   151→                                                         return true; // Swallow error
   152→                                                     });
   153→                                }));
   154→    }
   155→
   156→    /**
   157→     * Explicitly refreshes data from the backend and stores the latest snapshot in DB.
   158→     */
   159→    @Override
   160→    public Completable refresh(@NonNull String userId) {
   161→        manualRefreshProcessor.onNext(userId);
   162→        return Completable.complete();
   163→    }
   164→    // endregion
   165→
   166→    // region – Background synchronisation
   167→
   168→    /**
   169→     * Periodically invoked by WorkManager (or app foreground) to push any locally pending changes.
   170→     */
   171→    @Override
   172→    public Completable trySyncPendingEntries() {
   173→        return networkMonitor.isConnectedSingle()
   174→                .flatMapCompletable(isOnline -> {
   175→                    if (!isOnline) {
   176→                        return Completable.complete();
   177→                    }
   178→                    return journalDao.getPendingSync()
   179→                            .flatMapCompletable(pendingList -> {
   180→                                if (pendingList.isEmpty()) {
   181→                                    return Completable.complete();
   182→                                }
   183→                                return journalApi.upsertEntries(JournalEntryDto.fromEntities(pendingList))
   184→                                                 .map(JournalEntryDto::toEntities)
   185→                                                 .flatMapCompletable(serverEntities -> Completable.fromAction(() -> {
   186→                                                     // Mark as synced
   187→                                                     for (JournalEntryEntity entity : pendingList) {
   188→                                                         entity = entity.toBuilder().setPendingSync(false).build();
   189→                                                         journalDao.upsert(entity);
   190→                                                     }
   191→                                                     // Merge server authoritative state
   192→                                                     journalDao.upsertAll(serverEntities);
   193→                                                 }))
   194→                                                 .subscribeOn(Schedulers.io())
   195→                                                 .retryWhen(buildRetryStrategy("syncPending"));
   196→                            });
   197→                })
   198→                .subscribeOn(Schedulers.io());
   199→    }
   200→    // endregion
   201→
   202→    // region – Private helpers
   203→
   204→    /**
   205→     * Retrieves the full remote list (paged) and updates the local cache.
   206→     */
   207→    private Single<Boolean> pullLatestFromBackend(@NonNull String userId) {
   208→        return networkMonitor.isConnectedSingle()
   209→                .flatMap(isOnline -> {
   210→                    if (!isOnline) {
   211→                        Timber.d("Skipping pullLatest – offline");
   212→                        return Single.just(false);
   213→                    }
   214→
   215→                    return fetchPaged(userId, 1)
   216→                            .retryWhen(buildRetryStrategy("fetchPaged"))
   217→                            .map(serverEntities -> {
   218→                                appExecutors.diskIO().execute(() -> {
   219→                                    // Replace cache transactionally
   220→                                    journalDao.replaceForUser(userId, serverEntities);
   221→                                });
   222→                                return true;
   223→                            });
   224→                })
   225→                .subscribeOn(Schedulers.io());
   226→    }
   227→
   228→    /**
   229→     * Fetches all pages recursively.
   230→     */
   231→    private Single<List<JournalEntryEntity>> fetchPaged(String userId, int page) {
   232→        return journalApi.getEntries(userId, page, REMOTE_PAGE_SIZE)
   233→                         .map(JournalEntryDto::toEntities)
   234→                         .flatMap(list -> {
   235→                             if (list.size() < REMOTE_PAGE_SIZE) {
   236→                                 return Single.just(list); // Last page
   237→                             }
   238→                             return fetchPaged(userId, page + 1)
   239→                                     .map(next -> {
   240→                                         list.addAll(next);
   241→                                         return list;
   242→                                     });
   243→                         })
   244→                         .subscribeOn(Schedulers.io());
   245→    }
   246→
   247→    /**
   248→     * Builds an exponential back-off retry strategy for network operations.
   249→     */
   250→    private Flowable<Long> buildRetryStrategy(@NonNull String tag) {
   251→        return errors -> errors
   252→                .zipWith(Flowable.range(1, MAX_RETRY_COUNT), (throwable, retryCount) -> {
   253→                    if (retryCount == MAX_RETRY_COUNT) {
   254→                        throw new RuntimeException(throwable);
   255→                    }
   256→                    return retryCount;
   257→                })
   258→                .flatMap(retryCount -> {
   259→                    long delay = (long) Math.pow(2, retryCount) * RETRY_BACKOFF_MILLIS;
   260→                    Timber.w("%s – retry #%d in %d ms", tag, retryCount, delay);
   261→                    return Flowable.timer(delay, TimeUnit.MILLISECONDS);
   262→                });
   263→    }
   264→    // endregion
   265→
   266→    // region – Testing helpers
   267→    @VisibleForTesting
   268→    BehaviorProcessor<String> getManualRefreshProcessor() {
   269→        return manualRefreshProcessor;
   270→    }
   271→    // endregion
   272→}

